# Recipe — Presence with `waitForPresenceSync` helper

**Task:** Track presence between two clients; helper guarantees the sequencing rule for `leave`.

→ Back to `../index.md` | See lesson: `../lessons/lesson-03-presence.md`

---

```typescript
import { createClient, type RealtimeChannel } from '@supabase/supabase-js';

async function subscribeAndWait(ch: RealtimeChannel) {
  return new Promise<void>((res, rej) => {
    ch.subscribe((s, e) => {
      if (s === 'SUBSCRIBED') res();
      else if (s === 'CHANNEL_ERROR' || s === 'TIMED_OUT') rej(e ?? new Error(s));
    });
  });
}

/**
 * Wait until `key` appears in ch.presenceState().
 * Required before triggering a `leave` you expect to observe.
 * [Live verified, L2 BT-RT-L2-05/07; Gap #50]
 */
export async function waitForPresenceSync(
  ch: RealtimeChannel,
  key: string,
  timeoutMs = 5000,
): Promise<void> {
  const start = Date.now();
  while (Date.now() - start < timeoutMs) {
    const s = ch.presenceState() as Record<string, unknown[]>;
    if (Array.isArray(s[key]) && s[key].length > 0) return;
    await new Promise((r) => setTimeout(r, 50));
  }
  throw new Error(`presence key ${key} did not sync within ${timeoutMs} ms`);
}

// ----- Example flow -----

export async function presenceJoinLeaveDemo(topic: string) {
  const A = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_ANON_KEY!);
  const B = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_ANON_KEY!);

  const keyA = 'user-A';
  const keyB = 'user-B';

  const chA = A.channel(topic, { config: { presence: { key: keyA } } });
  const chB = B.channel(topic, { config: { presence: { key: keyB } } });

  let bLeaveA = false;
  chB.on('presence', { event: 'leave' }, ({ key }) => { if (key === keyA) bLeaveA = true; });

  await subscribeAndWait(chA);
  await chA.track({ name: 'Alice' });

  await subscribeAndWait(chB);
  await waitForPresenceSync(chB, keyA);    // ← B must observe A first

  await chA.untrack();                      // now triggers leave on B
  await new Promise((r) => setTimeout(r, 250));

  if (!bLeaveA) throw new Error('leave did not fire — check waitForPresenceSync');

  await A.removeAllChannels(); A.realtime.disconnect();
  await B.removeAllChannels(); B.realtime.disconnect();
}
```

