  },
  // Add more docs as needed
];

// src/retriever.ts — keyword overlap (swap for vector store when ready)
import { corpus, type Doc } from "./corpus.js";
const STOP = new Set(["the","a","an","is","are","of","in","to","and","or","for","on","with"]);
function tokens(s: string) { return s.toLowerCase().match(/\w+/g)?.filter(t => !STOP.has(t)) ?? []; }

export function keywordRetrieve(query: string, k: number): Doc[] {
  const qTokens = new Set(tokens(query));
  if (qTokens.size === 0) return [];
  return corpus
    .map(d => ({ d, score: tokens(d.content).filter(t => qTokens.has(t)).length / qTokens.size }))
    .filter(s => s.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, k)
    .map(s => s.d);
}
```

