# R-001: Minimal `traceable` wrap of an async function

The shortest path from "I have an async function" to "I have a LangSmith trace."

**Prerequisites**: `npm install langsmith@0.7.1`. `LANGSMITH_API_KEY` in `.env`.

```typescript
import "dotenv/config";
import { Client } from "langsmith";
import { traceable, getCurrentRunTree } from "langsmith/traceable";
import { RunTree } from "langsmith/run_trees";

const client = new Client();

async function slowAdd(a: number, b: number): Promise<number> {
  await new Promise(r => setTimeout(r, 50));
  return a + b;
}

let capturedRunId: string | undefined;
const wrapped = traceable(async (a: number, b: number) => {
  capturedRunId = getCurrentRunTree().id;   // capture INSIDE the body
  return slowAdd(a, b);
}, { name: "slowAdd", run_type: "chain" });

try {
  const result = await wrapped(2, 3);
  console.log({ result, runId: capturedRunId });
} finally {
  await RunTree.getSharedClient().flush();   // CRITICAL — G-001/G-002
}
```

**What gets stored** (verbatim from L1 — `03-pocs/L1-traceable-wrapper-live/source/evidence.md`):

```jsonc
{
  "name": "slowAdd",
  "inputs": { "args": [2, 3] },        // POSITIONAL args
  "outputs": { "outputs": 5 },          // PLURAL "outputs" key
  "run_type": "chain",
  "status": "success",
  // ...
}
```

**Notes**:

- `import { traceable } from "langsmith/traceable"` — NOT `"langsmith"` (G-003).
- Inputs are captured as positional `args: [...]`, not named keys. To use named keys, define the wrapped function with a single object argument: `traceable(({a, b}) => ...)`.
- Outputs key is `outputs` (plural), not `output` (singular).
- Use `getCurrentRunTree().id` to capture the run ID for later `readRun()` queries.
- Run is visible via `readRun(id)` after ~1-8 seconds (G-010).

**Evidence**: `03-pocs/L1-traceable-wrapper-live/surprises.md` (run shape details); `03-pocs/L1-traceable-wrapper-live/source/evidence.md` (verbatim readRun output).

## Code

```ts
import { createClient, type RealtimeChannel } from '@supabase/supabase-js';

const URL = process.env.SUPABASE_URL!;
const ANON = process.env.SUPABASE_ANON_KEY!;
const SR = process.env.SUPABASE_SERVICE_ROLE_KEY!;
const PAT = process.env.SUPABASE_ACCESS_TOKEN!;
const REF = process.env.SUPABASE_PROJECT_REF!;

const TABLE = `au_d05_events_${Date.now()}`;

async function mgmtSql(query: string) {
  const res = await fetch(`https://api.supabase.com/v1/projects/${REF}/database/query`, {
    method: 'POST',
    headers: { Authorization: `Bearer ${PAT}`, 'content-type': 'application/json' },
    body: JSON.stringify({ query }),
  });
  if (!res.ok && res.status !== 201) throw new Error(`mgmt SQL ${res.status}: ${await res.text()}`);
  return res.json();
}

async function subscribed(ch: RealtimeChannel, timeoutMs = 5000) {
  return new Promise<void>((resolve, reject) => {
    const t = setTimeout(() => reject(new Error('subscribe timeout')), timeoutMs);
    ch.subscribe((status, err) => {
      if (status === 'SUBSCRIBED') { clearTimeout(t); resolve(); }
      else if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') { clearTimeout(t); reject(err); }
    });
  });
}

async function main() {
  // 1) DDL via Mgmt SQL — table, REPLICA IDENTITY FULL, publication membership, schema cache reload
  await mgmtSql(`
    create table public.${TABLE} (
      id          bigserial primary key,
      kind        text not null,
      payload     jsonb,
      inserted_at timestamptz not null default now()
    );
  `);
  await mgmtSql(`alter table public.${TABLE} replica identity full;`);
  await mgmtSql(`alter publication supabase_realtime add table public.${TABLE};`);
  await mgmtSql(`notify pgrst, 'reload schema';`);

  // 2) Settle for publication-to-replication wiring
  await new Promise(r => setTimeout(r, 1500));

  // 3) Subscribe
  const supaSub = createClient(URL, ANON);
  const events: Array<{ eventType: string; new: any; old: any }> = [];
  const ch = supaSub
    .channel(`au-d05-events-watch`)
    .on('postgres_changes', { event: '*', schema: 'public', table: TABLE }, (p) => {
      events.push({ eventType: p.eventType, new: p.new, old: p.old });
    });
  await subscribed(ch);

  // 4) Public channel: 500 ms post-subscribe settle is sufficient
  await new Promise(r => setTimeout(r, 500));

  // 5) DML via PostgREST (NOT Mgmt API — Gap #49)
  const supaSvc = createClient(URL, SR, { auth: { persistSession: false } });
  const { data: row } = await supaSvc
    .from(TABLE)
    .insert({ kind: 'recipe-test', payload: { src: 'recipe' } })
    .select()
    .single();

  // 6) UPDATE and DELETE to exercise old payloads (FULL replica identity)
  await supaSvc.from(TABLE).update({ kind: 'recipe-test-updated' }).eq('id', row!.id);
  await supaSvc.from(TABLE).delete().eq('id', row!.id);

  // 7) Wait for events
  await new Promise(r => setTimeout(r, 2000));

  console.log({ event_count: events.length, types: events.map(e => e.eventType) });
  // Expect: 3 events — INSERT, UPDATE, DELETE
  // UPDATE.old has all 4 cols (FULL); DELETE.old has all 4 cols (FULL)

  // 8) Cleanup
  await supaSub.removeAllChannels();
  supaSub.realtime.disconnect();
  await mgmtSql(`alter publication supabase_realtime drop table public.${TABLE};`);
  await mgmtSql(`drop table public.${TABLE};`);
}

main().catch(console.error);
```

## Fix

1. Use `pathMap` form of `addConditionalEdges` — values in the `pathMap` are validated at compile time:

```typescript
graph.addConditionalEdges("classify", routeByIntent, {
  handleGreeting: "handleGreeting",
  handleQuestion: "handleQuestion",
  handleUnknown:  "handleUnknown",
});
```

2. Add an explicit `default` branch in your router:

```typescript
function routeByIntent(state) {
  const intent = state.intent;
  if (intent === "greeting") return "handleGreeting";
  if (intent === "question") return "handleQuestion";
  return "handleUnknown";   // always returns a registered node
}
```

3. Or use the explicit `END` / `__end__` constant when "do nothing more" is the right outcome.

