  }));
}

export async function joinTeamChannel(teamId: string, jwt: string, userKey: string) {
  const supa = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_ANON_KEY!);
  supa.realtime.setAuth(jwt);

  const topic = `au-d05-team-${teamId}`;
  const ch = supa.channel(topic, {
    config: {
      private: true,
      broadcast: { self: true },           // sender sees own chat msg (Gap #58)
      presence: { key: userKey },
    },
  });

  // Register all .on() BEFORE subscribe.
  const chatLog: any[] = [];
  const roster: Record<string, unknown[]> = {};
  const taskEvents: any[] = [];

  ch.on('broadcast', { event: 'chat' }, ({ payload }) => chatLog.push(payload))
    .on('presence', { event: 'sync' }, () => Object.assign(roster, ch.presenceState()))
    .on('postgres_changes',
      { event: '*', schema: 'public', table: 'au_d05_cap_tasks', filter: `team_id=eq.${teamId}` },
      (p) => taskEvents.push(p),
    );

  await subscribeAndWait(ch);

  // Private + postgres_changes: 1.5 s settle (Gap #59).
  await new Promise((r) => setTimeout(r, 1500));

  await ch.track({ name: 'me', at: new Date().toISOString() });

  return {
    client: supa,
    channel: ch,
    chatLog, roster, taskEvents,
    sendChat: (body: string) => ch.send({ type: 'broadcast', event: 'chat', payload: { body } }),
    addTask:  (title: string) => supa.from('au_d05_cap_tasks').insert({ team_id: teamId, title }),
  };
}
